const e=require("fs"),i=require("path"),n=__dirname,o=e.readdirSync(n).filter(e=>e.endsWith(".html"));let r=0;for(const t of o){const o=i.join(n,t);let c=e.readFileSync(o,"utf8");c.includes("favicon.jpg")&&(c=c.replace(/<link rel="icon" type="image\/jpeg" href="favicon\.jpg">/gi,'<link rel="icon" type="image/png" href="favicon.png">'),e.writeFileSync(o,c,"utf8"),r++)}console.log(`Updated ${r} HTML files to use favicon.png.`);